{"file_path": "D:/Documents/Dev/Projects/Work/Eaglepoint/w2t105/repo/backend/app/static/openapi.json", "content": "{
  "openapi": "3.0.3",
  "info": {
    "title": "W2T105 API",
    "version": "1.0.0",
    "description": "Community commerce platform API — authentication, user management, communities, catalog, inventory, commissions, messaging, content, and templates."
  },
  "servers": [
    { "url": "/api/v1", "description": "v1 API" }
  ],
  "components": {
    "securitySchemes": {
      "BearerAuth": {
        "type": "http",
        "scheme": "bearer"
      }
    },
    "schemas": {
      "RegisterRequest": {
        "type": "object",
        "required": ["username", "password"],
        "properties": {
          "username": { "type": "string", "minLength": 1, "maxLength": 64 },
          "password": { "type": "string" },
          "role": { "type": "string", "enum": ["Administrator", "Operations Manager", "Moderator", "Group Leader", "Staff", "Member"] }
        }
      },
      "LoginRequest": {
        "type": "object",
        "required": ["username", "password"],
        "properties": {
          "username": { "type": "string" },
          "password": { "type": "string" }
        }
      },
      "User": {
        "type": "object",
        "properties": {
          "id": { "type": "string" },
          "username": { "type": "string" },
          "role": { "type": "string" },
          "created_at": { "type": "string", "format": "date-time" }
        }
      },
      "LoginResponse": {
        "type": "object",
        "properties": {
          "token": { "type": "string" },
          "user": { "$ref": "#/components/schemas/User" }
        }
      },
      "ProductAttribute": {
        "type": "object",
        "required": ["key", "value"],
        "properties": {
          "key": { "type": "string", "minLength": 1 },
          "value": { "type": "string" }
        }
      },
      "CreateProduct": {
        "type": "object",
        "required": ["sku", "name", "brand", "category", "price_usd"],
        "properties": {
          "sku": { "type": "string", "minLength": 1, "maxLength": 128 },
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "brand": { "type": "string", "minLength": 1, "maxLength": 128 },
          "category": { "type": "string", "minLength": 1, "maxLength": 128 },
          "description": { "type": "string", "default": "" },
          "price_usd": { "type": "number", "minimum": 0 },
          "attributes": { "type": "array", "items": { "$ref": "#/components/schemas/ProductAttribute" }, "default": [] },
          "tags": { "type": "array", "items": { "type": "string" }, "default": [] }
        }
      },
      "UpdateProduct": {
        "type": "object",
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "brand": { "type": "string", "minLength": 1, "maxLength": 128 },
          "category": { "type": "string", "minLength": 1, "maxLength": 128 },
          "description": { "type": "string" },
          "price_usd": { "type": "number", "minimum": 0 },
          "attributes": { "type": "array", "items": { "$ref": "#/components/schemas/ProductAttribute" } },
          "tags": { "type": "array", "items": { "type": "string" } }
        }
      },
      "Product": {
        "type": "object",
        "properties": {
          "id": { "type": "string" },
          "sku": { "type": "string" },
          "name": { "type": "string" },
          "brand": { "type": "string" },
          "category": { "type": "string" },
          "description": { "type": "string" },
          "price_usd": { "type": "number" },
          "attributes": { "type": "array", "items": { "$ref": "#/components/schemas/ProductAttribute" } },
          "tags": { "type": "array", "items": { "type": "string" } },
          "created_at": { "type": "string", "format": "date-time" }
        }
      },
      "CreateWarehouse": {
        "type": "object",
        "required": ["name", "location"],
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "location": { "type": "string", "minLength": 1, "maxLength": 512 },
          "notes": { "type": "string", "nullable": true },
          "community_id": { "type": "string", "nullable": true }
        }
      },
      "Warehouse": {
        "type": "object",
        "properties": {
          "id": { "type": "string" },
          "name": { "type": "string" },
          "location": { "type": "string" },
          "notes": { "type": "string", "nullable": true },
          "community_id": { "type": "string", "nullable": true }
        }
      },
      "CreateBin": {
        "type": "object",
        "required": ["bin_code"],
        "properties": {
          "bin_code": { "type": "string", "minLength": 1, "maxLength": 64 },
          "description": { "type": "string", "nullable": true }
        }
      },
      "Bin": {
        "type": "object",
        "properties": {
          "id": { "type": "string" },
          "warehouse_id": { "type": "string" },
          "bin_code": { "type": "string" },
          "description": { "type": "string", "nullable": true }
        }
      },
      "Receipt": {
        "type": "object",
        "required": ["sku_id", "warehouse_id", "quantity"],
        "properties": {
          "sku_id": { "type": "string" },
          "warehouse_id": { "type": "string" },
          "quantity": { "type": "integer", "minimum": 1 },
          "bin_id": { "type": "string", "nullable": true },
          "lot_number": { "type": "string", "nullable": true },
          "costing_method": { "type": "string", "enum": ["fifo", "moving_average"], "default": "fifo" },
          "unit_cost_usd": { "type": "number", "default": 0 },
          "barcode": { "type": "string", "nullable": true },
          "rfid": { "type": "string", "nullable": true },
          "serial_numbers": { "nullable": true },
          "occurred_at": { "type": "string", "nullable": true },
          "notes": { "type": "string", "nullable": true }
        }
      },
      "Issue": {
        "type": "object",
        "required": ["sku_id", "warehouse_id", "quantity"],
        "properties": {
          "sku_id": { "type": "string" },
          "warehouse_id": { "type": "string" },
          "quantity": { "type": "integer", "minimum": 1 },
          "bin_id": { "type": "string", "nullable": true },
          "lot_number": { "type": "string", "nullable": true },
          "barcode": { "type": "string", "nullable": true },
          "rfid": { "type": "string", "nullable": true },
          "serial_numbers": { "nullable": true },
          "reference": { "type": "string", "nullable": true },
          "occurred_at": { "type": "string", "nullable": true }
        }
      },
      "Transfer": {
        "type": "object",
        "required": ["sku_id", "from_warehouse_id", "to_warehouse_id", "quantity"],
        "properties": {
          "sku_id": { "type": "string" },
          "from_warehouse_id": { "type": "string" },
          "to_warehouse_id": { "type": "string" },
          "quantity": { "type": "integer", "minimum": 1 },
          "from_bin_id": { "type": "string", "nullable": true },
          "to_bin_id": { "type": "string", "nullable": true },
          "lot_number": { "type": "string", "nullable": true },
          "barcode": { "type": "string", "nullable": true },
          "rfid": { "type": "string", "nullable": true },
          "reference": { "type": "string", "nullable": true },
          "notes": { "type": "string", "nullable": true },
          "occurred_at": { "type": "string", "nullable": true }
        }
      },
      "Adjustment": {
        "type": "object",
        "required": ["sku_id", "warehouse_id", "quantity_delta"],
        "properties": {
          "sku_id": { "type": "string" },
          "warehouse_id": { "type": "string" },
          "quantity_delta": { "type": "integer" },
          "bin_id": { "type": "string", "nullable": true },
          "reason": { "type": "string", "nullable": true },
          "occurred_at": { "type": "string", "nullable": true }
        }
      },
      "CycleCountLine": {
        "type": "object",
        "required": ["sku_id", "counted_qty"],
        "properties": {
          "sku_id": { "type": "string" },
          "bin_id": { "type": "string", "nullable": true },
          "counted_qty": { "type": "integer" },
          "variance_reason": { "type": "string", "nullable": true }
        }
      },
      "CycleCount": {
        "type": "object",
        "required": ["warehouse_id", "counted_at", "lines"],
        "properties": {
          "warehouse_id": { "type": "string" },
          "counted_at": { "type": "string" },
          "lines": { "type": "array", "items": { "$ref": "#/components/schemas/CycleCountLine" } }
        }
      },
      "CreateCommunity": {
        "type": "object",
        "required": ["name", "address_line1", "city", "state", "zip"],
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "address_line1": { "type": "string", "minLength": 1, "maxLength": 512 },
          "address_line2": { "type": "string", "nullable": true },
          "city": { "type": "string", "minLength": 1, "maxLength": 128 },
          "state": { "type": "string", "pattern": "^[A-Z]{2}$" },
          "zip": { "type": "string", "pattern": "^\\d{5}(-\\d{4})?$" },
          "service_hours": { "type": "object", "default": {} },
          "fulfillment_scope": { "type": "string", "default": "" }
        }
      },
      "UpdateCommunity": {
        "type": "object",
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "address_line1": { "type": "string", "minLength": 1, "maxLength": 512 },
          "address_line2": { "type": "string", "nullable": true },
          "city": { "type": "string", "minLength": 1, "maxLength": 128 },
          "state": { "type": "string", "pattern": "^[A-Z]{2}$" },
          "zip": { "type": "string", "pattern": "^\\d{5}(-\\d{4})?$" },
          "service_hours": { "type": "object" },
          "fulfillment_scope": { "type": "string" }
        }
      },
      "Community": {
        "type": "object",
        "properties": {
          "id": { "type": "string" },
          "name": { "type": "string" },
          "address_line1": { "type": "string" },
          "address_line2": { "type": "string", "nullable": true },
          "city": { "type": "string" },
          "state": { "type": "string" },
          "zip": { "type": "string" },
          "service_hours": { "type": "object" },
          "fulfillment_scope": { "type": "string" },
          "created_at": { "type": "string", "format": "date-time" }
        }
      },
      "CreateServiceArea": {
        "type": "object",
        "required": ["name", "address_line1", "city", "state", "zip"],
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "address_line1": { "type": "string", "minLength": 1, "maxLength": 512 },
          "city": { "type": "string", "minLength": 1, "maxLength": 128 },
          "state": { "type": "string", "pattern": "^[A-Z]{2}$" },
          "zip": { "type": "string", "pattern": "^\\d{5}(-\\d{4})?$" },
          "notes": { "type": "string", "nullable": true }
        }
      },
      "UpdateServiceArea": {
        "type": "object",
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "address_line1": { "type": "string", "minLength": 1, "maxLength": 512 },
          "city": { "type": "string", "minLength": 1, "maxLength": 128 },
          "state": { "type": "string", "pattern": "^[A-Z]{2}$" },
          "zip": { "type": "string", "pattern": "^\\d{5}(-\\d{4})?$" },
          "notes": { "type": "string", "nullable": true }
        }
      },
      "ServiceArea": {
        "type": "object",
        "properties": {
          "id": { "type": "string" },
          "community_id": { "type": "string" },
          "name": { "type": "string" },
          "address_line1": { "type": "string" },
          "city": { "type": "string" },
          "state": { "type": "string" },
          "zip": { "type": "string" },
          "notes": { "type": "string", "nullable": true }
        }
      },
      "TemplateField": {
        "type": "object",
        "required": ["name", "type"],
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "type": { "type": "string", "enum": ["text", "number", "textarea", "date", "boolean", "enum", "select"] },
          "required": { "type": "boolean", "default": false },
          "enum": { "type": "array", "items": { "type": "string" }, "nullable": true }
        }
      },
      "CreateTemplate": {
        "type": "object",
        "required": ["name"],
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "fields": { "type": "array", "items": { "$ref": "#/components/schemas/TemplateField" }, "default": [] }
        }
      },
      "UpdateTemplate": {
        "type": "object",
        "properties": {
          "name": { "type": "string", "minLength": 1, "maxLength": 256 },
          "fields": { "type": "array", "items": { "$ref": "#/components/schemas/TemplateField" } }
        }
      },
      "PaginatedParams": {
        "type": "object",
        "properties": {
          "page": { "type": "integer", "default": 1 },
          "page_size": { "type": "integer", "default": 20, "maximum": 100 }
        }
      },
      "Error": {
        "type": "object",
        "properties": {
          "error": { "type": "string" }
        }
      }
    }
  },
  "tags": [
    { "name": "Health", "description": "Liveness and readiness probes" },
    { "name": "Auth", "description": "Authentication — register, login, logout" },
    { "name": "Users", "description": "User management" },
    { "name": "Communities", "description": "Communities, service areas, leader bindings, and memberships" },
    { "name": "Catalog", "description": "Product catalog management" },
    { "name": "Search", "description": "Product search, autocomplete, trending, and history" },
    { "name": "Inventory", "description": "Warehouses, bins, stock transactions, and queries" },
    { "name": "Commission", "description": "Commission rules, settlements, disputes" },
    { "name": "Messaging", "description": "Asynchronous message queue" },
    { "name": "Content", "description": "CMS content with versioning and attachments" },
    { "name": "Templates", "description": "Content templates with versioning, migrations, and attachments" },
    { "name": "Admin", "description": "Audit log, tickets, and reports" }
  ],
  "paths": {
    "/auth/register": {
      "post": {
        "tags": ["Auth"],
        "summary": "Register a new user",
        "operationId": "register",
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "$ref": "#/components/schemas/RegisterRequest" } } }
        },
        "responses": {
          "201": { "description": "User created", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/User" } } } },
          "422": { "description": "Validation error" }
        }
      }
    },
    "/auth/login": {
      "post": {
        "tags": ["Auth"],
        "summary": "Log in and receive a bearer token",
        "operationId": "login",
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "$ref": "#/components/schemas/LoginRequest" } } }
        },
        "responses": {
          "200": { "description": "Login successful", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/LoginResponse" } } } },
          "401": { "description": "Invalid credentials" }
        }
      }
    },
    "/auth/logout": {
      "post": {
        "tags": ["Auth"],
        "summary": "Invalidate the current token",
        "operationId": "logout",
        "security": [{ "BearerAuth": [] }],
        "responses": {
          "204": { "description": "Logged out" },
          "401": { "description": "Unauthorized" }
        }
      }
    },
    "/users": {
      "get": {
        "tags": ["Users"],
        "summary": "List users (Admin / Ops Manager)",
        "operationId": "listUsers",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "role", "in": "query", "schema": { "type": "string" } },
          { "name": "page", "in": "query", "schema": { "type": "integer", "default": 1 } },
          { "name": "page_size", "in": "query", "schema": { "type": "integer", "default": 20, "maximum": 100 } },
          { "name": "include_deleted", "in": "query", "schema": { "type": "boolean" }, "description": "Requires Administrator role" }
        ],
        "responses": {
          "200": { "description": "Paginated user list" }
        }
      }
    },
    "/users/{user_id}": {
      "get": {
        "tags": ["Users"],
        "summary": "Get a user by ID",
        "operationId": "getUser",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "user_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": { "description": "User details", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/User" } } } },
          "404": { "description": "Not found" }
        }
      },
      "patch": {
        "tags": ["Users"],
        "summary": "Update a user",
        "operationId": "updateUser",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "user_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "type": "object" } } }
        },
        "responses": {
          "200": { "description": "Updated user", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/User" } } } }
        }
      },
      "delete": {
        "tags": ["Users"],
        "summary": "Soft-delete a user (Admin only)",
        "operationId": "deleteUser",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "user_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "204": { "description": "Deleted" }
        }
      }
    },
    "/users/{user_id}/password": {
      "patch": {
        "tags": ["Users"],
        "summary": "Change a user's password",
        "operationId": "changePassword",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "user_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "type": "object", "properties": { "current_password": { "type": "string" }, "new_password": { "type": "string" } } } } }
        },
        "responses": {
          "204": { "description": "Password changed" }
        }
      }
    },
    "/communities": {
      "post": {
        "tags": ["Communities"],
        "summary": "Create a community",
        "operationId": "createCommunity",
        "security": [{ "BearerAuth": [] }],
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "$ref": "#/components/schemas/CreateCommunity" } } }
        },
        "responses": {
          "201": { "description": "Community created", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/Community" } } } }
        }
      },
      "get": {
        "tags": ["Communities"],
        "summary": "List communities",
        "operationId": "listCommunities",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "city", "in": "query", "schema": { "type": "string" } },
          { "name": "state", "in": "query", "schema": { "type": "string" } },
          { "name": "page", "in": "query", "schema": { "type": "integer", "default": 1 } },
          { "name": "page_size", "in": "query", "schema": { "type": "integer", "default": 20, "maximum": 100 } }
        ],
        "responses": {
          "200": { "description": "Paginated community list" }
        }
      }
    },
    "/communities/{community_id}": {
      "get": {
        "tags": ["Communities"],
        "summary": "Get community detail",
        "operationId": "getCommunity",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "community_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": { "description": "Community detail", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/Community" } } } }
        }
      },
      "patch": {
        "tags": ["Communities"],
        "summary": "Update a community",
        "operationId": "updateCommunity",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "community_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "$ref": "#/components/schemas/UpdateCommunity" } } }
        },
        "responses": {
          "200": { "description": "Updated community", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/Community" } } } }
        }
      },
      "delete": {
        "tags": ["Communities"],
        "summary": "Delete a community (Admin only)",
        "operationId": "deleteCommunity",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "community_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "204": { "description": "Deleted" }
        }
      }
    },
    "/communities/{community_id}/service-areas": {
      "post": {
        "tags": ["Communities"],
        "summary": "Add a service area",
        "operationId": "createServiceArea",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "community_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "$ref": "#/components/schemas/CreateServiceArea" } } }
        },
        "responses": {
          "201": { "description": "Service area created", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/ServiceArea" } } } }
        }
      },
      "get": {
        "tags": ["Communities"],
        "summary": "List service areas for a community",
        "operationId": "listServiceAreas",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "community_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": { "description": "Service area list" }
        }
      }
    },
    "/communities/{community_id}/service-areas/{area_id}": {
      "patch": {
        "tags": ["Communities"],
        "summary": "Update a service area",
        "operationId": "updateServiceArea",
        "security": [{ "BearerAuth": [] }],
        "parameters": [
          { "name": "community_id", "in": "path", "required": true, "schema": { "type": "string" } },
          { "name": "area_id", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": { "application/json": { "schema": { "$ref": "#/components/schemas/UpdateServiceArea" } } }
        },
        "responses": {
          "200": { "description": "Updated service area", "content": { "application/json": { "schema": { "$ref": "#/components/schemas/ServiceArea" } } } }
        }
      },
      "delete": {
        "tags": ["Communities"],
        "summary": "Delete a service area (Admin only)",
        "operationId": "deleteServiceArea",
